#include<bits/stdc++.h>
using namespace std;
int a[1000010],in[1000010],ans[1000010];
vector<int> mp[1000010];
int main()
{
	int n,tot=0;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
		if(a[i]==-1)
		{
			a[i]=a[i-1]+1;
		}
	}
	stack<int> s;
	for(int i=1;i<=n;i++)
	{
		int lst=0;
		for(int j=1;j<=a[i-1]-a[i]+1;j++)
		{
			lst=s.top();
			s.pop();
		}
		if(lst)
		{
			mp[i].push_back(lst);
			in[lst]++;
		}
		if(!s.empty())
		{
			mp[s.top()].push_back(i);
			in[i]++;
		}
		s.push(i);
	}
	priority_queue<int,vector<int>,greater<int>> q;
	for(int i=1;i<=n;i++)
	{
		if(in[i]==0)
		{
			q.push(i);
		}
	}
	while(!q.empty())
	{
		int t=q.top();
		q.pop();
		ans[t]=++tot;
		for(int i:mp[t])
		{
			in[i]--;
			if(in[i]==0)
			{
				q.push(i);
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		printf("%d ",ans[i]);
	}
	return 0;
}
